import { useState, useEffect } from "react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from "recharts";

const GAS_URL = "https://script.google.com/macros/s/AKfycbyMe6WfZmNJfzmdWLmUIbW4O-FZpDTcDOItsMzouwM07hM7cBC2ht5uFsiV9YjNtgNj/exec";
const LOCATIONS = ["自宅", "病院", "DS", "その他"];
const DRACULA_IMG = "data:image/png;base64,";

function nowDatetimeLocal() {
  const d = new Date();
  const pad = n => String(n).padStart(2,'0');
  return d.getFullYear()+"-"+pad(d.getMonth()+1)+"-"+pad(d.getDate())+"T"+pad(d.getHours())+":"+pad(d.getMinutes());
}

const defaultForm = { systolic:"", diastolic:"", pulse:"", location:"自宅", memo:"", datetime:nowDatetimeLocal() };

function formatDate(iso) {
  const d = new Date(iso);
  return (d.getMonth()+1)+"/"+(d.getDate());
}
function formatDateFull(iso) {
  const d = new Date(iso);
  const hh = String(d.getHours()).padStart(2,'0');
  const mm = String(d.getMinutes()).padStart(2,'0');
  return d.getFullYear()+"/"+(d.getMonth()+1)+"/"+d.getDate()+" "+hh+":"+mm;
}
function BPStatus(sys, dia) {
  if (sys < 120 && dia < 80) return { label:"正常", color:"#6ee7b7" };
  if (sys < 130 && dia < 80) return { label:"正常高値", color:"#a3e635" };
  if (sys < 140 || dia < 90) return { label:"高値血圧", color:"#fbbf24" };
  return { label:"高血圧", color:"#ef4444" };
}

function DiffChip({ diff }) {
  if (diff == null) return null;
  if (diff === 0) return <span style={{ fontSize:11, color:"#9ca3af", background:"#2d1b2e", borderRadius:6, padding:"2px 8px" }}>― 変化なし</span>;
  const up = diff > 0;
  return (
    <span style={{ fontSize:11, color:up?"#ef4444":"#6ee7b7", background:up?"#3d0a0a":"#0a2d1e", borderRadius:6, padding:"2px 8px", fontWeight:700 }}>
      {up?"▲":"▼"} {Math.abs(diff)}
    </span>
  );
}

export default function App() {
  const [records, setRecords] = useState([]);
  const [form, setForm] = useState(defaultForm);
  const [tab, setTab] = useState("input");
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    const style = document.createElement('style');
    style.textContent = `
      @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700;900&family=Noto+Sans+JP:wght@300;400;700&display=swap');
      * { box-sizing: border-box; }
      input[type=number]::-webkit-inner-spin-button,
      input[type=number]::-webkit-outer-spin-button { -webkit-appearance: none; margin: 0; }
      input[type=number] { -moz-appearance: textfield; }
      @keyframes batfly { 0%,100% { transform: translateY(0) rotate(-8deg); } 50% { transform: translateY(-10px) rotate(8deg); } }
      @keyframes pulse-glow { 0%,100% { box-shadow: 0 0 8px #c0392b44; } 50% { box-shadow: 0 0 22px #c0392b99; } }
      .bat { animation: batfly 5s ease-in-out infinite; display:inline-block; }
      .glow-card { animation: pulse-glow 3s ease-in-out infinite; }
    `;
    document.head.appendChild(style);
    loadRecords();
  }, []);

  async function loadRecords() {
    setLoading(true);
    setError("");
    try {
      const res = await fetch(GAS_URL);
      const data = await res.json();
      if (data.status === "ok") {
        const rows = data.rows.slice(1).filter(r => r[0]).map(r => ({
          id: r[0], date: r[0],
          systolic: +r[1], diastolic: +r[2], pulse: +r[3],
          location: r[4] || "自宅", memo: r[5] || ""
        }));
        rows.sort((a,b) => new Date(b.date) - new Date(a.date));
        setRecords(rows);
      }
    } catch(e) {
      setError("データ読み込み失敗。ネット接続を確認してください。");
    }
    setLoading(false);
  }

  async function handleSubmit() {
    if (!form.systolic || !form.diastolic || !form.pulse) return;
    setSaving(true);
    setError("");
    const chosenDate = form.datetime ? new Date(form.datetime).toISOString() : new Date().toISOString();
    try {
      if (editId) {
        await fetch(GAS_URL, { method:"POST", body: JSON.stringify({ action:"delete", date:editId }) });
      }
      await fetch(GAS_URL, {
        method:"POST",
        body: JSON.stringify({ action:"add", date:chosenDate, systolic:+form.systolic, diastolic:+form.diastolic, pulse:+form.pulse, location:form.location, memo:form.memo })
      });
      await loadRecords();
      setForm({...defaultForm, datetime:nowDatetimeLocal()});
      setEditId(null);
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
      setTab("list");
    } catch(e) {
      setError("保存失敗。もう一度試してください。");
    }
    setSaving(false);
  }

  function handleEdit(r) {
    const d = new Date(r.date);
    const pad = n => String(n).padStart(2,'0');
    const dtLocal = d.getFullYear()+"-"+pad(d.getMonth()+1)+"-"+pad(d.getDate())+"T"+pad(d.getHours())+":"+pad(d.getMinutes());
    setForm({ systolic:r.systolic, diastolic:r.diastolic, pulse:r.pulse, location:r.location, memo:r.memo||"", datetime:dtLocal });
    setEditId(r.id);
    setTab("input");
  }

  async function handleDelete(id) {
    if (!confirm("削除しますか？")) return;
    setSaving(true);
    try {
      await fetch(GAS_URL, { method:"POST", body: JSON.stringify({ action:"delete", date:id }) });
      await loadRecords();
    } catch(e) { setError("削除失敗。"); }
    setSaving(false);
  }

  const latest = records[0];
  const status = latest ? BPStatus(latest.systolic, latest.diastolic) : null;

  function getDiff(key) {
    const cur = +form[key];
    const pre = latest?.[key];
    if (!cur || !pre || editId) return null;
    return cur - pre;
  }

  const chartData = [...records].reverse().slice(-30).map(r => ({
    date: formatDate(r.date), 収縮期: r.systolic, 拡張期: r.diastolic, 脈拍: r.pulse,
  }));

  const C = { bg:"#0d0010", bg2:"#120018", bg3:"#1a0a1e", border:"#4a1030", red:"#c0392b", redLight:"#e74c3c", redDark:"#7b0d1e", text:"#e8d5f0", muted:"#7b3f6e", dim:"#4a1a44" };

  if (loading) return (
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100vh",background:C.bg,color:C.muted,fontFamily:"'Noto Sans JP',sans-serif",gap:16}}>
      <img src={DRACULA_IMG} alt="ドラキュラ" style={{width:80,height:80,objectFit:"contain"}} className="bat" />
      <span style={{fontSize:14,letterSpacing:2}}>読み込み中…</span>
    </div>
  );

  return (
    <div style={{ fontFamily:"'Noto Sans JP',sans-serif", background:C.bg, minHeight:"100vh", color:C.text, paddingBottom:60,
      backgroundImage:"radial-gradient(ellipse at 15% 5%, #3d0a2e33 0%, transparent 45%), radial-gradient(ellipse at 85% 90%, #1a003333 0%, transparent 45%)" }}>

      <div style={{ background:"linear-gradient(180deg,#1a0022,"+C.bg+")", padding:"20px 20px 16px", borderBottom:"1px solid "+C.border+"55", position:"relative", overflow:"hidden" }}>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <img src={DRACULA_IMG} alt="ドラキュラ" style={{width:64,height:64,objectFit:"contain"}} />
          <div>
            <div style={{ fontFamily:"'Cinzel',serif", fontSize:22, fontWeight:900,
              background:"linear-gradient(135deg,"+C.red+",#922b21,"+C.redLight+")",
              WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent", backgroundClip:"text", letterSpacing:3 }}>
              🩸 BLOOD DIARY
            </div>
            <div style={{ fontSize:10, color:C.muted, letterSpacing:2 }}>～ 血圧管理帳 ～</div>
          </div>
        </div>

        {latest && (
          <div className="glow-card" style={{ marginTop:12, background:"linear-gradient(135deg,"+C.bg3+","+C.bg2+")",
            border:"1px solid "+C.border, borderRadius:14, padding:"12px 16px", display:"inline-block" }}>
            <div style={{ fontSize:10, color:C.muted, marginBottom:6 }}>最新記録　{formatDateFull(latest.date)}　📍{latest.location}</div>
            <div style={{ display:"flex", gap:16, alignItems:"baseline", flexWrap:"wrap" }}>
              <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
                <span style={{ fontSize:11, color:C.muted }}>収縮期</span>
                <span style={{ fontSize:28, fontWeight:700, color:status.color, fontFamily:"'Cinzel',serif" }}>{latest.systolic}</span>
              </div>
              <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
                <span style={{ fontSize:11, color:C.muted }}>拡張期</span>
                <span style={{ fontSize:22, fontWeight:700, color:"#c084fc", fontFamily:"'Cinzel',serif" }}>{latest.diastolic}</span>
              </div>
              <div style={{ display:"flex", alignItems:"baseline", gap:4 }}>
                <span style={{ fontSize:11, color:C.muted }}>脈拍</span>
                <span style={{ fontSize:18, fontWeight:700, color:"#fbbf24", fontFamily:"'Cinzel',serif" }}>{latest.pulse}</span>
              </div>
            </div>
            <div style={{ marginTop:6 }}>
              <span style={{ background:status.color+"22", color:status.color, borderRadius:6, padding:"2px 10px", fontSize:11, fontWeight:700 }}>{status.label}</span>
            </div>
          </div>
        )}
        {error && <div style={{ marginTop:8, color:"#ef4444", fontSize:12 }}>⚠️ {error}</div>}
        <button onClick={loadRecords} style={{ position:"absolute", right:12, top:12, background:"none", border:"1px solid "+C.border, borderRadius:8, color:C.muted, fontSize:11, padding:"4px 10px", cursor:"pointer", fontFamily:"inherit" }}>🔄 更新</button>
      </div>

      <div style={{ display:"flex", background:C.bg, borderBottom:"1px solid "+C.border+"44" }}>
        {[["input","🩸 入力"],["list","📜 履歴"],["graph","📈 グラフ"]].map(([key,label]) => (
          <button key={key} onClick={() => setTab(key)} style={{
            flex:1, padding:"13px 0", background:"none", border:"none", cursor:"pointer",
            fontFamily:"'Noto Sans JP',sans-serif", fontSize:12,
            color: tab===key ? C.redLight : C.muted,
            borderBottom: tab===key ? "2px solid "+C.red : "2px solid transparent",
            fontWeight: tab===key ? 700 : 400,
          }}>{label}</button>
        ))}
      </div>

      <div style={{ padding:"20px 16px", maxWidth:560, margin:"0 auto" }}>

        {tab==="input" && (
          <div>
            <div style={{ fontFamily:"'Cinzel',serif", fontSize:13, color:C.red, marginBottom:18, letterSpacing:2 }}>
              {editId ? "✏️ EDIT RECORD" : "➕ NEW RECORD"}
            </div>

            <div style={{ marginBottom:18 }}>
              <label style={{ fontSize:11, color:C.muted, display:"block", marginBottom:6, letterSpacing:1 }}>📅 測定日時</label>
              <input type="datetime-local" value={form.datetime}
                onChange={e => setForm(f => ({...f, datetime:e.target.value}))}
                style={{ width:"100%", background:C.bg2, border:"1px solid "+C.border,
                  borderRadius:10, padding:"11px 14px", color:C.text, fontSize:14,
                  fontFamily:"'Noto Sans JP',sans-serif", outline:"none", colorScheme:"dark", boxSizing:"border-box" }} />
            </div>

            {latest && !editId && (form.systolic || form.diastolic || form.pulse) && (
              <div style={{ background:C.bg3, border:"1px solid "+C.border, borderRadius:12, padding:"12px 16px", marginBottom:18, position:"relative", overflow:"hidden" }}>
                <div style={{ position:"absolute", top:0, left:0, right:0, height:1, background:"linear-gradient(90deg,transparent,"+C.red+"66,transparent)" }} />
                <div style={{ fontSize:10, color:C.muted, marginBottom:10, letterSpacing:1 }}>📊 前回（{formatDateFull(latest.date)}）との比較</div>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8 }}>
                  {[["収縮期","systolic","#e74c3c"],["拡張期","diastolic","#c084fc"],["脈拍","pulse","#fbbf24"]].map(([label,key,color]) => (
                    <div key={key} style={{ textAlign:"center" }}>
                      <div style={{ fontSize:10, color:C.muted, marginBottom:4 }}>{label}</div>
                      <div style={{ fontSize:11, color:C.dim, marginBottom:4 }}>前回 <span style={{ color }}>{latest[key]}</span></div>
                      <DiffChip diff={getDiff(key)} />
                    </div>
                  ))}
                </div>
              </div>
            )}

            {[["systolic","収縮期血圧（上）","mmHg","#e74c3c"],["diastolic","拡張期血圧（下）","mmHg","#c084fc"],["pulse","脈拍","bpm","#fbbf24"]].map(([key,label,unit,color]) => (
              <div key={key} style={{ marginBottom:16 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                  <label style={{ fontSize:11, color:C.muted, letterSpacing:1 }}>{label}</label>
                  {latest && !editId && form[key] && (
                    <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                      <span style={{ fontSize:10, color:C.dim }}>前回 {latest[key]}</span>
                      <DiffChip diff={getDiff(key)} />
                    </div>
                  )}
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <input type="number" inputMode="numeric" value={form[key]}
                    onChange={e => setForm(f => ({...f,[key]:e.target.value}))}
                    style={{ flex:1, background:C.bg2, border:"1px solid "+(form[key]?color+"66":C.border),
                      borderRadius:10, padding:"13px 16px", color, fontSize:26, fontWeight:700,
                      outline:"none", fontFamily:"'Cinzel',serif",
                      boxShadow:form[key]?"0 0 10px "+color+"33":"none", transition:"all .2s" }}
                    placeholder="---" />
                  <span style={{ color:C.dim, fontSize:12, minWidth:36 }}>{unit}</span>
                </div>
              </div>
            ))}

            <div style={{ marginBottom:16 }}>
              <label style={{ fontSize:11, color:C.muted, display:"block", marginBottom:8, letterSpacing:1 }}>測定場所</label>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                {LOCATIONS.map(loc => (
                  <button key={loc} onClick={() => setForm(f => ({...f,location:loc}))} style={{
                    padding:"8px 16px", borderRadius:20,
                    border:"1px solid "+(form.location===loc?C.red:C.border),
                    background:form.location===loc?"#3d0a0a":C.bg2,
                    color:form.location===loc?C.redLight:C.muted,
                    fontSize:12, cursor:"pointer", fontFamily:"'Noto Sans JP',sans-serif", transition:"all .2s"
                  }}>{loc}</button>
                ))}
              </div>
            </div>

            <div style={{ marginBottom:24 }}>
              <label style={{ fontSize:11, color:C.muted, display:"block", marginBottom:6, letterSpacing:1 }}>メモ</label>
              <textarea value={form.memo} onChange={e => setForm(f => ({...f,memo:e.target.value}))} rows={3}
                placeholder="気になること、体調など…"
                style={{ width:"100%", background:C.bg2, border:"1px solid "+C.border, borderRadius:10,
                  padding:"12px 16px", color:C.text, fontSize:13, fontFamily:"'Noto Sans JP',sans-serif",
                  resize:"none", outline:"none", boxSizing:"border-box" }} />
            </div>

            <button onClick={handleSubmit} disabled={!form.systolic||!form.diastolic||!form.pulse||saving}
              style={{ width:"100%", padding:"15px",
                background:(!form.systolic||!form.diastolic||!form.pulse||saving)?C.bg3:"linear-gradient(135deg,"+C.redDark+","+C.red+")",
                border:"none", borderRadius:12,
                color:(!form.systolic||!form.diastolic||!form.pulse||saving)?C.dim:"#ffe8e8",
                fontSize:15, fontWeight:700, cursor:"pointer", fontFamily:"'Cinzel',serif", letterSpacing:3,
                boxShadow:(!form.systolic||!form.diastolic||!form.pulse||saving)?"none":"0 4px 20px "+C.red+"44" }}>
              {saving ? "保存中…🩸" : editId ? "UPDATE 🩸" : "RECORD 🩸"}
            </button>
            {editId && (
              <button onClick={() => { setEditId(null); setForm({...defaultForm, datetime:nowDatetimeLocal()}); }} style={{
                width:"100%", marginTop:10, padding:"12px", background:"none",
                border:"1px solid "+C.border, borderRadius:12, color:C.muted,
                fontSize:13, cursor:"pointer", fontFamily:"'Noto Sans JP',sans-serif" }}>キャンセル</button>
            )}
            {saved && <div style={{ textAlign:"center", color:"#6ee7b7", marginTop:14, fontSize:13, letterSpacing:1 }}>🩸 スプレッドシートに記録しました！</div>}
          </div>
        )}

        {tab==="list" && (
          <div>
            <div style={{ fontFamily:"'Cinzel',serif", fontSize:13, color:C.red, marginBottom:16, letterSpacing:2 }}>
              📜 RECORDS ({records.length})
            </div>
            {records.length === 0 && (
              <div style={{ color:C.muted, textAlign:"center", marginTop:60, fontSize:13 }}>
                <img src={DRACULA_IMG} alt="" style={{width:60,height:60,objectFit:"contain",marginBottom:12,opacity:0.5}} className="bat" />
                <div>まだ記録がありません</div>
              </div>
            )}
            {records.map((r,i) => {
              const s = BPStatus(r.systolic, r.diastolic);
              const p = records[i+1];
              return (
                <div key={r.id} style={{ background:"linear-gradient(135deg,"+C.bg3+","+C.bg2+")",
                  borderRadius:12, padding:"14px 16px", marginBottom:12,
                  border:"1px solid "+C.border, position:"relative", overflow:"hidden" }}>
                  <div style={{ position:"absolute", top:0, left:0, right:0, height:1,
                    background:"linear-gradient(90deg,transparent,"+s.color+"55,transparent)" }} />
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:10, color:C.muted, marginBottom:6 }}>{formatDateFull(r.date)}　📍{r.location}</div>
                      <div style={{ display:"flex", alignItems:"baseline", gap:4, flexWrap:"wrap" }}>
                        <span style={{ fontSize:26, fontWeight:700, color:s.color, fontFamily:"'Cinzel',serif" }}>{r.systolic}</span>
                        <span style={{ color:C.dim }}>/</span>
                        <span style={{ fontSize:20, fontWeight:600, color:"#c084fc", fontFamily:"'Cinzel',serif" }}>{r.diastolic}</span>
                        <span style={{ fontSize:10, color:C.dim }}>mmHg</span>
                        <span style={{ fontSize:13, color:"#fbbf24", marginLeft:8 }}>♥ {r.pulse} bpm</span>
                      </div>
                      {p && (
                        <div style={{ display:"flex", gap:6, marginTop:6, flexWrap:"wrap", alignItems:"center" }}>
                          <span style={{ fontSize:10, color:C.dim }}>前回比：</span>
                          <DiffChip diff={r.systolic-p.systolic} />
                          <DiffChip diff={r.diastolic-p.diastolic} />
                          <DiffChip diff={r.pulse-p.pulse} />
                        </div>
                      )}
                      <div style={{ marginTop:6 }}>
                        <span style={{ fontSize:10, background:s.color+"22", color:s.color, borderRadius:5, padding:"2px 8px" }}>{s.label}</span>
                      </div>
                      {r.memo && <div style={{ fontSize:11, color:C.muted, marginTop:6 }}>💬 {r.memo}</div>}
                    </div>
                    <div style={{ display:"flex", gap:6, marginLeft:8 }}>
                      <button onClick={() => handleEdit(r)} style={{ background:"#1a0a2e", border:"1px solid #4a1a6e", color:"#c084fc", borderRadius:8, padding:"6px 10px", fontSize:11, cursor:"pointer", fontFamily:"inherit" }}>編集</button>
                      <button onClick={() => handleDelete(r.id)} style={{ background:"#2d0a0a", border:"1px solid "+C.redDark, color:C.redLight, borderRadius:8, padding:"6px 10px", fontSize:11, cursor:"pointer", fontFamily:"inherit" }}>削除</button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {tab==="graph" && (
          <div>
            <div style={{ fontFamily:"'Cinzel',serif", fontSize:13, color:C.red, marginBottom:16, letterSpacing:2 }}>
              📈 GRAPH (直近30件)
            </div>
            {chartData.length < 2
              ? <div style={{ color:C.muted, textAlign:"center", marginTop:60, fontSize:13 }}>
                  <img src={DRACULA_IMG} alt="" style={{width:60,height:60,objectFit:"contain",marginBottom:12,opacity:0.5}} className="bat" />
                  <div>2件以上記録するとグラフが表示されます</div>
                </div>
              : <>
                <div style={{ background:C.bg3, border:"1px solid "+C.border, borderRadius:12, padding:"16px 4px", marginBottom:14 }}>
                  <div style={{ fontSize:10, color:C.muted, marginBottom:8, paddingLeft:12 }}>血圧 (mmHg)</div>
                  <ResponsiveContainer width="100%" height={200}>
                    <LineChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#2d0a2e" />
                      <XAxis dataKey="date" stroke={C.muted} tick={{ fontSize:10, fill:C.muted }} />
                      <YAxis stroke={C.muted} tick={{ fontSize:10, fill:C.muted }} domain={[40,200]} />
                      <Tooltip contentStyle={{ background:C.bg3, border:"1px solid "+C.border, borderRadius:8, fontSize:11, color:C.text }} />
                      <Legend wrapperStyle={{ fontSize:11 }} />
                      <ReferenceLine y={140} stroke="#ef4444" strokeDasharray="4 4" strokeOpacity={0.4} />
                      <ReferenceLine y={90} stroke="#fbbf24" strokeDasharray="4 4" strokeOpacity={0.4} />
                      <Line type="monotone" dataKey="収縮期" stroke="#e74c3c" strokeWidth={2} dot={{ r:3, fill:"#e74c3c" }} />
                      <Line type="monotone" dataKey="拡張期" stroke="#c084fc" strokeWidth={2} dot={{ r:3, fill:"#c084fc" }} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
                <div style={{ background:C.bg3, border:"1px solid "+C.border, borderRadius:12, padding:"16px 4px" }}>
                  <div style={{ fontSize:10, color:C.muted, marginBottom:8, paddingLeft:12 }}>脈拍 (bpm)</div>
                  <ResponsiveContainer width="100%" height={150}>
                    <LineChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#2d0a2e" />
                      <XAxis dataKey="date" stroke={C.muted} tick={{ fontSize:10, fill:C.muted }} />
                      <YAxis stroke={C.muted} tick={{ fontSize:10, fill:C.muted }} domain={[40,120]} />
                      <Tooltip contentStyle={{ background:C.bg3, border:"1px solid "+C.border, borderRadius:8, fontSize:11, color:C.text }} />
                      <Line type="monotone" dataKey="脈拍" stroke="#fbbf24" strokeWidth={2} dot={{ r:3, fill:"#fbbf24" }} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              </>
            }
          </div>
        )}
      </div>
    </div>
  );
}
